dslRule:
/*!id: jdt.internal.bindingcomparator.capturebinding.position-to-end*/
/*!description: Updates internal JDT BindingComparator logic to compare 'end' property instead of 'position' for CaptureBinding, enhancing robustness of wildcard capture handling.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, bugfix*/
$captureBinding.position == $captureBinding2.position :: inClass("org.eclipse.jdt.core.dom.BindingComparator")
=> $captureBinding.end == $captureBinding2.end
;;

/*!id: jdt.internal.typebinding.capture.add-argument*/
/*!description: Adds a new integer argument to the internal TypeBinding.capture() method call, enhancing robustness for wildcard captures.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, bugfix*/
$expressionType.capture($scope, 0) :: inClass("org.eclipse.jdt.core.dom.TypeBinding")
=> $expressionType.capture($scope, 0, 0)
;;

@id: jdt.internal.checks.validatemodifiesfiles.addmonitor
@severity: info
org.eclipse.jdt.internal.corext.util.Checks.validateModifiesFiles($files, $context)
=> org.eclipse.jdt.internal.corext.util.Checks.validateModifiesFiles($files, $context, pm)
;;

// Note: This rule assumes 'pm' is an IProgressMonitor variable available in the scope.
// The commit also implies similar changes for 'Checks.validateEdit()'.

dslRuleAfterChange:
/* This is an illustrative example of what a rule might look like if the DSL were extended to support the required semantic checks and conditional sub-expression rewrites. */
$Type $var = $init; :: sourceVersionGE(10) && isAssignedToLocalVariable() && !$Type.isName("var") && !$Type.isArrayDeclaration() && $Type.isTypeCompatible($init) && !$init.requiresNumericPostfix($Type.getResolvedBinding())
=> var $var = $init;
;;
